import {
  ChangeDetectionStrategy,
  Component,
  computed,
  DestroyRef,
  inject,
  input,
  model,
  output,
  signal,
} from '@angular/core';
import { ControlValueAccessor } from '@angular/forms';
import { injectFormControl } from '../../utils/form-control';
import { mergeClasses } from '../../utils/merge-classes';
import { ButtonComponent } from '../button';
import { LabelComponent } from '../label';
import { ImageUploadCropComponent } from './image-upload-crop.component';
import { imageUploadVariants, type ImageUploadVariants } from './image-upload.variants';
import { ACCEPT_PRESETS, ACCEPT_LABELS, type AcceptPreset, type UploadFile, type UploadError } from './image-upload.types';

let _idCounter = 0;

@Component({
  selector: 'n-image-upload',
  standalone: true,
  imports: [ButtonComponent, LabelComponent, ImageUploadCropComponent],
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents' },
  template: `
    <div [class]="wrapperClasses()" data-slot="root">

      @if (nLabel()) {
        <n-label [nRequired]="nRequired()" [nDisabled]="isDisabled()">
          {{ nLabel() }}
        </n-label>
      }

      @if (nVariant() === 'dropzone') {

        <div
          [class]="dropzoneClasses()"
          data-slot="control"
          role="button"
          [attr.tabindex]="isDisabled() ? -1 : 0"
          [attr.aria-disabled]="isDisabled() ? true : null"
          [attr.aria-invalid]="hasError() ? true : null"
          [attr.aria-describedby]="describedBy()"
          (click)="!isDisabled() && fileInput.click()"
          (keydown.enter)="$event.preventDefault(); !isDisabled() && fileInput.click()"
          (keydown.space)="$event.preventDefault(); !isDisabled() && fileInput.click()"
          (dragenter)="onDragEnter($event)"
          (dragover)="onDragOver($event)"
          (dragleave)="onDragLeave($event)"
          (drop)="onDrop($event)"
        >
          <input
            #fileInput
            type="file"
            class="hidden"
            [accept]="_resolvedAccept()"
            [multiple]="nMultiple()"
            [disabled]="isDisabled()"
            (change)="onFileInput($event)"
          />

          @if (nValue().length === 0) {
            <div class="flex flex-col items-center gap-3 text-center pointer-events-none select-none">
              <div class="flex h-12 w-12 items-center justify-center rounded-full bg-muted">
                <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" class="text-muted-foreground" aria-hidden="true">
                  <path d="M4 14.899A7 7 0 1 1 15.71 8h1.79a4.5 4.5 0 0 1 2.5 8.242"/>
                  <path d="M12 12v9"/>
                  <path d="m16 16-4-4-4 4"/>
                </svg>
              </div>
              <div>
                <p class="text-sm">
                  <span class="font-medium text-foreground">Clique para selecionar</span>
                  <span class="text-muted-foreground"> ou arraste aqui</span>
                </p>
                @if (nAccept() && nAccept() !== 'all') {
                  <p class="text-xs text-muted-foreground mt-0.5">{{ _acceptLabel() }}</p>
                }
                @if (nMaxSize() > 0) {
                  <p class="text-xs text-muted-foreground mt-0.5">Máximo {{ formatSize(nMaxSize()) }}</p>
                }
              </div>
            </div>
          } @else {
            <div class="w-full flex flex-col gap-2" (click)="$event.stopPropagation()" (keydown)="$event.stopPropagation()">

              @for (file of nValue(); track file.name + file.size; let i = $index) {
                <div class="flex items-center gap-3 rounded-md border border-border bg-background/80 p-2.5" data-slot="item">

                  @if (nPreview() === 'image') {
                    <img [src]="file.preview" [alt]="file.name" class="h-11 w-11 rounded-md object-cover shrink-0 border border-border" />
                  } @else {
                    <div class="flex h-11 w-11 shrink-0 items-center justify-center rounded-md bg-muted border border-border">
                      <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="text-muted-foreground" aria-hidden="true">
                        <rect width="18" height="18" x="3" y="3" rx="2" ry="2"/>
                        <circle cx="9" cy="9" r="2"/>
                        <path d="m21 15-3.086-3.086a2 2 0 0 0-2.828 0L6 21"/>
                      </svg>
                    </div>
                  }

                  <div class="flex-1 min-w-0">
                    <p class="text-sm font-medium text-foreground truncate leading-tight">{{ file.name }}</p>
                    <p class="text-xs text-muted-foreground mt-0.5">{{ formatSize(file.size) }}</p>
                    @if (nProgress() >= 0) {
                      <div class="mt-1.5 h-1.5 w-full rounded-full bg-muted overflow-hidden" data-slot="progress">
                        <div class="h-full rounded-full bg-primary transition-all duration-300" [style.width.%]="nProgress()"></div>
                      </div>
                    }
                  </div>

                  <div class="flex items-center gap-1 shrink-0">
                    @if (nCrop()) {
                      <button
                        n-button
                        nVariant="ghost"
                        nSize="icon"
                        nClass="h-7 w-7 text-muted-foreground"
                        aria-label="Recortar imagem"
                        (nClick)="openCrop(file)"
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M6 2v14a2 2 0 0 0 2 2h14"/><path d="M18 22V8a2 2 0 0 0-2-2H2"/></svg>
                      </button>
                    }
                    <button
                      n-button
                      nVariant="ghost"
                      nSize="icon"
                      nClass="h-7 w-7 text-muted-foreground hover:bg-destructive/10 hover:text-destructive"
                      [attr.aria-label]="'Remover ' + file.name"
                      (nClick)="removeFile(i)"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
                    </button>
                  </div>

                </div>
              }

              @if (nMultiple() && nValue().length < nMaxFiles()) {
                <button
                  n-button
                  nVariant="ghost"
                  nSize="sm"
                  nClass="self-start text-muted-foreground gap-1.5 px-2"
                  (nClick)="fileInput.click()"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="10"/><path d="M8 12h8"/><path d="M12 8v8"/></svg>
                  Adicionar mais
                </button>
              }

            </div>
          }
        </div>

      } @else {

        <!-- Avatar variant -->
        <div
          [class]="avatarClasses()"
          data-slot="control"
          role="button"
          [attr.tabindex]="isDisabled() ? -1 : 0"
          [attr.aria-label]="nAriaLabel() || nLabel() || 'Selecionar foto'"
          [attr.aria-disabled]="isDisabled() ? true : null"
          [attr.aria-invalid]="hasError() ? true : null"
          (click)="!isDisabled() && avatarInput.click()"
          (keydown.enter)="$event.preventDefault(); !isDisabled() && avatarInput.click()"
          (keydown.space)="$event.preventDefault(); !isDisabled() && avatarInput.click()"
        >
          <input
            #avatarInput
            type="file"
            class="hidden"
            [accept]="_resolvedAccept()"
            [disabled]="isDisabled()"
            (change)="onFileInput($event)"
          />

          @if (nValue()[0] && nPreview() === 'image') {
            <img [src]="nValue()[0].preview" [alt]="nValue()[0].name" class="h-full w-full object-cover" />
          } @else {
            <svg xmlns="http://www.w3.org/2000/svg" width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" class="text-muted-foreground" aria-hidden="true">
              <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/>
              <circle cx="12" cy="7" r="4"/>
            </svg>
          }

          @if (!isDisabled()) {
            <button
              n-button
              nVariant="default"
              nSize="icon"
              nClass="absolute bottom-0.5 right-0.5 h-6 w-6 rounded-full border-2 border-background"
              aria-label="Alterar foto"
              tabindex="-1"
              (nClick)="$event.stopPropagation(); avatarInput.click()"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M17 3a2.85 2.85 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/></svg>
            </button>
          }

          @if (nCrop() && nValue()[0]) {
            <button
              n-button
              nVariant="outline"
              nSize="icon"
              nClass="absolute top-0.5 right-0.5 h-6 w-6 rounded-full text-muted-foreground"
              aria-label="Recortar foto"
              tabindex="-1"
              (nClick)="$event.stopPropagation(); openCrop(nValue()[0])"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M6 2v14a2 2 0 0 0 2 2h14"/><path d="M18 22V8a2 2 0 0 0-2-2H2"/></svg>
            </button>
          }

        </div>

      }

      @if (hasError()) {
        <p [id]="errorId()" class="mt-1 text-xs text-destructive animate-error-in" role="alert" data-slot="error">
          {{ nError() }}
        </p>
      }

      @if (nHint() && !hasError()) {
        <p [id]="hintId()" class="mt-1 text-xs text-muted-foreground" data-slot="hint">
          {{ nHint() }}
        </p>
      }

    </div>

    @if (_cropTarget()) {
      <n-image-upload-crop
        [nFile]="_cropTarget()!"
        [nAspectRatio]="nCropAspectRatio()"
        (confirm)="onCropConfirm($event)"
        (cancel)="onCropCancel()"
      />
    }
  `,
})
export class ImageUploadComponent implements ControlValueAccessor {
  readonly nVariant         = input<ImageUploadVariants['nVariant']>('dropzone');
  readonly nSize            = input<ImageUploadVariants['nSize']>('default');
  readonly nAccept          = input<string>('image/*');
  readonly nMaxSize         = input<number>(0);
  readonly nMultiple        = input<boolean>(false);
  readonly nMaxFiles        = input<number>(10);
  readonly nMinWidth        = input<number>(0);
  readonly nMinHeight       = input<number>(0);
  readonly nMaxWidth        = input<number>(0);
  readonly nMaxHeight       = input<number>(0);
  readonly nPreview         = input<'image' | 'icon'>('image');
  readonly nProgress        = input<number>(-1);
  readonly nCrop            = input<boolean>(false);
  readonly nCropAspectRatio = input<number | null>(null);
  readonly nDisabled        = input<boolean>(false);
  readonly nRequired        = input<boolean>(false);
  readonly nLabel           = input<string>('');
  readonly nError           = input<string | null>(null);
  readonly nHint            = input<string | null>(null);
  readonly nClass           = input<string>('');
  readonly nAriaLabel       = input<string>('');
  readonly nId              = input<string>('');

  readonly nValue = model<UploadFile[]>([]);

  readonly nFileSelect = output<File[]>();
  readonly nFileCrop   = output<Blob>();
  readonly nFileReject = output<UploadError[]>();

  private readonly _form       = injectFormControl<UploadFile[]>(this);
  private readonly _destroyRef = inject(DestroyRef);
  private readonly _staticId   = `n-image-upload-${++_idCounter}`;

  protected readonly _cropTarget = signal<UploadFile | null>(null);
  private _dragCounter = 0;

  protected readonly isDisabled  = computed(() => this.nDisabled() || this._form.disabledByForm());
  protected readonly hasError    = computed(() => !!this.nError() || (this._form.controlInvalid() && this._form.controlTouched()));
  protected readonly elementId   = computed(() => this.nId() || this._staticId);
  protected readonly errorId     = computed(() => `${this.elementId()}-error`);
  protected readonly hintId      = computed(() => `${this.elementId()}-hint`);

  protected readonly describedBy = computed(() => {
    if (this.hasError()) return this.errorId();
    if (this.nHint())    return this.hintId();
    return null;
  });

  protected readonly wrapperClasses = computed(() =>
    mergeClasses('flex flex-col gap-1.5', this.nClass()),
  );

  protected readonly dropzoneClasses = computed(() =>
    mergeClasses(
      imageUploadVariants({ nVariant: 'dropzone', nSize: this.nSize() }),
      this.hasError() && 'border-destructive',
      this.isDisabled() && 'cursor-not-allowed opacity-50',
      this.nValue().length > 0 && 'items-stretch justify-start',
    ),
  );

  protected readonly avatarClasses = computed(() =>
    mergeClasses(
      imageUploadVariants({ nVariant: 'avatar', nSize: this.nSize() }),
      this.hasError() && 'border-destructive',
      this.isDisabled() && 'cursor-not-allowed opacity-50',
    ),
  );

  protected readonly _resolvedAccept = computed(() =>
    ACCEPT_PRESETS[this.nAccept() as AcceptPreset] ?? this.nAccept(),
  );

  protected readonly _acceptLabel = computed(() =>
    ACCEPT_LABELS[this.nAccept() as AcceptPreset] ?? this.nAccept(),
  );

  constructor() {
    this._destroyRef.onDestroy(() => {
      for (const f of this.nValue()) URL.revokeObjectURL(f.preview);
    });
  }

  protected onDragEnter(e: DragEvent): void {
    e.preventDefault();
    this._dragCounter++;
    if (!this.isDisabled()) {
      (e.currentTarget as HTMLElement).classList.add('border-primary', 'bg-primary/5');
    }
  }

  protected onDragOver(e: DragEvent): void {
    e.preventDefault();
  }

  protected onDragLeave(e: DragEvent): void {
    this._dragCounter--;
    if (this._dragCounter <= 0) {
      this._dragCounter = 0;
      (e.currentTarget as HTMLElement).classList.remove('border-primary', 'bg-primary/5');
    }
  }

  protected onDrop(e: DragEvent): void {
    e.preventDefault();
    this._dragCounter = 0;
    (e.currentTarget as HTMLElement).classList.remove('border-primary', 'bg-primary/5');
    if (this.isDisabled()) return;
    const files = e.dataTransfer?.files;
    if (files?.length) void this._processFiles(files);
  }

  protected onFileInput(e: Event): void {
    const files = (e.target as HTMLInputElement).files;
    if (files?.length) void this._processFiles(files);
    (e.target as HTMLInputElement).value = '';
  }

  protected removeFile(index: number): void {
    const files = [...this.nValue()];
    const removed = files.splice(index, 1)[0];
    if (removed?.preview) URL.revokeObjectURL(removed.preview);
    this._updateValue(files);
    this._form.notifyTouched();
  }

  protected openCrop(file: UploadFile): void {
    this._cropTarget.set(file);
  }

  protected onCropConfirm(blob: Blob): void {
    const target = this._cropTarget();
    if (!target) return;

    const croppedFile = new File([blob], target.name, { type: blob.type });
    const preview     = URL.createObjectURL(blob);
    const updated: UploadFile = { file: croppedFile, preview, name: target.name, size: blob.size, type: blob.type };

    URL.revokeObjectURL(target.preview);
    const files = this.nValue().map(f => f === target ? updated : f);
    this._updateValue(files);
    this.nFileCrop.emit(blob);
    this._cropTarget.set(null);
  }

  protected onCropCancel(): void {
    this._cropTarget.set(null);
  }

  protected formatSize(bytes: number): string {
    if (bytes < 1024)           return `${bytes} B`;
    if (bytes < 1024 * 1024)    return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  }

  private _updateValue(files: UploadFile[]): void {
    this.nValue.set(files);
    this._form.notifyChange(files);
  }

  private async _processFiles(rawFiles: FileList | File[]): Promise<void> {
    const list    = Array.from(rawFiles);
    const current = this.nValue();
    const slots   = this.nMultiple() ? this.nMaxFiles() - current.length : 1;

    const candidates = list.slice(0, slots);
    const rejected: UploadError[] = list.slice(slots).map(file => ({
      file, reason: 'count', message: `Limite de ${this.nMaxFiles()} arquivo(s) atingido.`,
    }));

    const accepted: UploadFile[] = [];

    for (const file of candidates) {
      if (!this._matchesAccept(file)) {
        rejected.push({ file, reason: 'type', message: `Tipo "${file.type}" não é aceito.` });
        continue;
      }
      if (this.nMaxSize() > 0 && file.size > this.nMaxSize()) {
        rejected.push({ file, reason: 'size', message: `Arquivo excede ${this.formatSize(this.nMaxSize())}.` });
        continue;
      }
      if (file.type.startsWith('image/') && (this.nMinWidth() || this.nMinHeight() || this.nMaxWidth() || this.nMaxHeight())) {
        const dimErr = await this._checkDimensions(file);
        if (dimErr) { rejected.push({ file, reason: 'dimensions', message: dimErr }); continue; }
      }
      const preview = URL.createObjectURL(file);
      accepted.push({ file, preview, name: file.name, size: file.size, type: file.type });
    }

    if (rejected.length) this.nFileReject.emit(rejected);

    if (accepted.length) {
      const newFiles = this.nMultiple() ? [...current, ...accepted] : accepted;
      this._updateValue(newFiles);
      this.nFileSelect.emit(accepted.map(f => f.file));
    }
  }

  private _matchesAccept(file: File): boolean {
    const accept = this._resolvedAccept().trim();
    if (!accept || accept === '*' || accept === '*/*') return true;
    return accept.split(',').some(token => {
      const t = token.trim();
      if (t.endsWith('/*'))   return file.type.startsWith(t.slice(0, -1));
      if (t.startsWith('.'))  return file.name.toLowerCase().endsWith(t.toLowerCase());
      return file.type === t;
    });
  }

  private _checkDimensions(file: File): Promise<string | null> {
    return new Promise(resolve => {
      const url = URL.createObjectURL(file);
      const img = new Image();
      img.onload = () => {
        URL.revokeObjectURL(url);
        const { naturalWidth: w, naturalHeight: h } = img;
        if (this.nMinWidth()  && w < this.nMinWidth())  return resolve(`Largura mínima: ${this.nMinWidth()}px.`);
        if (this.nMinHeight() && h < this.nMinHeight()) return resolve(`Altura mínima: ${this.nMinHeight()}px.`);
        if (this.nMaxWidth()  && w > this.nMaxWidth())  return resolve(`Largura máxima: ${this.nMaxWidth()}px.`);
        if (this.nMaxHeight() && h > this.nMaxHeight()) return resolve(`Altura máxima: ${this.nMaxHeight()}px.`);
        resolve(null);
      };
      img.onerror = () => { URL.revokeObjectURL(url); resolve(null); };
      img.src = url;
    });
  }

  writeValue(value: UploadFile[] | null | undefined): void {
    for (const f of this.nValue()) URL.revokeObjectURL(f.preview);
    this.nValue.set(value ?? []);
  }

  registerOnChange(fn: (v: UploadFile[]) => void): void { this._form.setOnChange(fn); }
  registerOnTouched(fn: () => void): void               { this._form.setOnTouched(fn); }
  setDisabledState(isDisabled: boolean): void           { this._form.setDisabledByForm(isDisabled); }
}

import {
  afterNextRender,
  ChangeDetectionStrategy,
  Component,
  computed,
  ElementRef,
  inject,
  input,
  output,
  PLATFORM_ID,
  viewChild,
} from '@angular/core';
import { isPlatformBrowser } from '@angular/common';
import { ButtonComponent } from '../button';
import type { UploadFile } from './image-upload.types';

const HANDLE_SIZE = 8;
const MAX_W = 640;
const MAX_H = 480;

type ResizeHandle = 'tl' | 'tr' | 'bl' | 'br' | 'move' | null;

interface CropRect { x: number; y: number; w: number; h: number }

@Component({
  selector: 'n-image-upload-crop',
  standalone: true,
  imports: [ButtonComponent],
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    class: 'fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm',
    tabindex: '-1',
    '(keydown.escape)': 'cancel.emit()',
    '(keydown.enter)': '$event.preventDefault(); confirmCrop()',
  },
  template: `
    <div class="bg-background rounded-xl shadow-2xl p-4 flex flex-col gap-4 max-w-2xl w-full mx-4 max-h-[90vh] overflow-auto">

      <div class="flex items-center justify-between">
        <p class="text-sm font-medium text-foreground">Recortar imagem</p>
        @if (aspectRatioLabel()) {
          <span class="text-xs text-muted-foreground bg-muted rounded-md px-2 py-0.5">{{ aspectRatioLabel() }}</span>
        }
      </div>

      <div class="flex items-center justify-center rounded-md bg-black overflow-hidden">
        <canvas
          #cropCanvas
          class="max-w-full max-h-[60vh] cursor-crosshair touch-none block"
          (pointerdown)="onPointerDown($event)"
          (pointermove)="onPointerMove($event)"
          (pointerup)="onPointerUp()"
          (lostpointercapture)="onPointerUp()"
        ></canvas>
      </div>

      <p class="text-xs text-center text-muted-foreground">
        Arraste para mover · Cantos para redimensionar · Enter para confirmar
      </p>

      <div class="flex justify-end gap-2">
        <button n-button nVariant="outline" nSize="sm" type="button" (click)="cancel.emit()">Cancelar</button>
        <button n-button nSize="sm" type="button" (click)="confirmCrop()">Confirmar recorte</button>
      </div>

    </div>
  `,
})
export class ImageUploadCropComponent {
  readonly nFile        = input.required<UploadFile>();
  readonly nAspectRatio = input<number | null>(null);

  readonly confirm = output<Blob>();
  readonly cancel  = output<void>();

  private readonly _canvasRef  = viewChild.required<ElementRef<HTMLCanvasElement>>('cropCanvas');
  private readonly _platformId = inject(PLATFORM_ID);

  private _img: HTMLImageElement | null = null;
  private _ctx: CanvasRenderingContext2D | null = null;
  private _crop: CropRect = { x: 0, y: 0, w: 0, h: 0 };
  private _dragHandle: ResizeHandle = null;
  private _dragStartX = 0;
  private _dragStartY = 0;
  private _dragStartCrop: CropRect = { x: 0, y: 0, w: 0, h: 0 };

  protected readonly aspectRatioLabel = computed(() => {
    const r = this.nAspectRatio();
    if (!r) return '';
    const presets: [number, string][] = [
      [1, '1:1'], [4 / 3, '4:3'], [3 / 2, '3:2'],
      [16 / 9, '16:9'], [9 / 16, '9:16'], [2 / 3, '2:3'],
    ];
    for (const [val, label] of presets) {
      if (Math.abs(val - r) < 0.01) return label;
    }
    return r.toFixed(2);
  });

  constructor() {
    afterNextRender(() => {
      if (!isPlatformBrowser(this._platformId)) return;
      this._loadImage();
    });
  }

  private _loadImage(): void {
    const img = new Image();
    img.onload = () => {
      this._img = img;
      const canvas = this._canvasRef().nativeElement;
      const scale = Math.min(1, MAX_W / img.naturalWidth, MAX_H / img.naturalHeight);
      canvas.width  = Math.round(img.naturalWidth * scale);
      canvas.height = Math.round(img.naturalHeight * scale);
      this._ctx = canvas.getContext('2d');
      this._initCrop(canvas.width, canvas.height);
      this._draw();
      // Ensure host is focused for keyboard events
      (canvas.closest('[tabindex]') as HTMLElement | null)?.focus();
    };
    img.onerror = () => this.cancel.emit();
    img.src = this.nFile().preview;
  }

  private _initCrop(cw: number, ch: number): void {
    const ratio = this.nAspectRatio();
    const pad = 0.1;
    if (ratio) {
      const maxW = cw * (1 - pad * 2);
      const maxH = ch * (1 - pad * 2);
      let w = maxW;
      let h = w / ratio;
      if (h > maxH) { h = maxH; w = h * ratio; }
      this._crop = { x: (cw - w) / 2, y: (ch - h) / 2, w, h };
    } else {
      this._crop = { x: cw * pad, y: ch * pad, w: cw * (1 - pad * 2), h: ch * (1 - pad * 2) };
    }
  }

  private _handles(): Record<string, { x: number; y: number }> {
    const { x, y, w, h } = this._crop;
    return { tl: { x, y }, tr: { x: x + w, y }, bl: { x, y: y + h }, br: { x: x + w, y: y + h } };
  }

  private _hitTest(px: number, py: number): ResizeHandle {
    const hit = HANDLE_SIZE + 6;
    for (const [key, { x, y }] of Object.entries(this._handles())) {
      if (Math.abs(px - x) <= hit && Math.abs(py - y) <= hit) return key as ResizeHandle;
    }
    const { x, y, w, h } = this._crop;
    if (px >= x && px <= x + w && py >= y && py <= y + h) return 'move';
    return null;
  }

  private _canvasPoint(e: PointerEvent): { x: number; y: number } {
    const canvas = this._canvasRef().nativeElement;
    const rect = canvas.getBoundingClientRect();
    return {
      x: (e.clientX - rect.left) * (canvas.width / rect.width),
      y: (e.clientY - rect.top) * (canvas.height / rect.height),
    };
  }

  protected onPointerDown(e: PointerEvent): void {
    e.preventDefault();
    const canvas = this._canvasRef().nativeElement;
    canvas.setPointerCapture(e.pointerId);
    const { x, y } = this._canvasPoint(e);
    this._dragHandle     = this._hitTest(x, y);
    this._dragStartX     = x;
    this._dragStartY     = y;
    this._dragStartCrop  = { ...this._crop };
  }

  protected onPointerMove(e: PointerEvent): void {
    if (!this._dragHandle) return;
    e.preventDefault();
    const canvas = this._canvasRef().nativeElement;
    const cw = canvas.width;
    const ch = canvas.height;
    const { x, y } = this._canvasPoint(e);
    const dx = x - this._dragStartX;
    const dy = y - this._dragStartY;
    const sr = this._dragStartCrop;
    const ratio = this.nAspectRatio();
    const MIN = 20;

    let nx = sr.x, ny = sr.y, nw = sr.w, nh = sr.h;

    switch (this._dragHandle) {
      case 'move':
        nx = Math.max(0, Math.min(cw - sr.w, sr.x + dx));
        ny = Math.max(0, Math.min(ch - sr.h, sr.y + dy));
        break;
      case 'tl':
        nw = Math.max(MIN, sr.w - dx);
        nh = ratio ? nw / ratio : Math.max(MIN, sr.h - dy);
        nx = sr.x + sr.w - nw;
        ny = sr.y + sr.h - nh;
        break;
      case 'tr':
        nw = Math.max(MIN, sr.w + dx);
        nh = ratio ? nw / ratio : Math.max(MIN, sr.h - dy);
        ny = sr.y + sr.h - nh;
        break;
      case 'bl':
        nw = Math.max(MIN, sr.w - dx);
        nh = ratio ? nw / ratio : Math.max(MIN, sr.h + dy);
        nx = sr.x + sr.w - nw;
        break;
      case 'br':
        nw = Math.max(MIN, sr.w + dx);
        nh = ratio ? nw / ratio : Math.max(MIN, sr.h + dy);
        break;
    }

    // Clamp to canvas bounds
    if (nx < 0)         { nw += nx; if (ratio) nh = nw / ratio; nx = 0; }
    if (ny < 0)         { nh += ny; if (ratio) nw = nh * ratio; ny = 0; }
    if (nx + nw > cw)   nw = cw - nx;
    if (ny + nh > ch)   nh = ch - ny;

    this._crop = { x: nx, y: ny, w: Math.max(MIN, nw), h: Math.max(MIN, nh) };
    this._draw();
  }

  protected onPointerUp(): void {
    this._dragHandle = null;
  }

  private _draw(): void {
    const ctx = this._ctx;
    const img = this._img;
    if (!ctx || !img) return;
    const canvas = this._canvasRef().nativeElement;
    const cw = canvas.width;
    const ch = canvas.height;
    const { x, y, w, h } = this._crop;

    ctx.clearRect(0, 0, cw, ch);

    // Draw dimmed background
    ctx.drawImage(img, 0, 0, cw, ch);
    ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
    ctx.fillRect(0, 0, cw, ch);

    // Reveal original image inside crop rect
    ctx.save();
    ctx.beginPath();
    ctx.rect(x, y, w, h);
    ctx.clip();
    ctx.drawImage(img, 0, 0, cw, ch);
    ctx.restore();

    // Crop border
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.9)';
    ctx.lineWidth = 1.5;
    ctx.strokeRect(x + 0.5, y + 0.5, w - 1, h - 1);

    // Rule-of-thirds grid
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.25)';
    ctx.lineWidth = 0.5;
    for (let i = 1; i < 3; i++) {
      ctx.beginPath(); ctx.moveTo(x + w * (i / 3), y); ctx.lineTo(x + w * (i / 3), y + h); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(x, y + h * (i / 3)); ctx.lineTo(x + w, y + h * (i / 3)); ctx.stroke();
    }

    // Corner handles
    ctx.fillStyle = 'white';
    for (const { x: hx, y: hy } of Object.values(this._handles())) {
      ctx.fillRect(hx - HANDLE_SIZE / 2, hy - HANDLE_SIZE / 2, HANDLE_SIZE, HANDLE_SIZE);
    }
  }

  confirmCrop(): void {
    const img = this._img;
    if (!img) return;
    const canvas = this._canvasRef().nativeElement;
    const scaleX = img.naturalWidth  / canvas.width;
    const scaleY = img.naturalHeight / canvas.height;
    const sx = Math.round(this._crop.x * scaleX);
    const sy = Math.round(this._crop.y * scaleY);
    const sw = Math.round(this._crop.w * scaleX);
    const sh = Math.round(this._crop.h * scaleY);

    const offscreen = document.createElement('canvas');
    offscreen.width  = sw;
    offscreen.height = sh;
    const ctx = offscreen.getContext('2d')!;
    ctx.drawImage(img, sx, sy, sw, sh, 0, 0, sw, sh);
    offscreen.toBlob(blob => { if (blob) this.confirm.emit(blob); }, 'image/jpeg', 0.92);
  }
}

import { cva, type VariantProps } from 'class-variance-authority';

export const imageUploadVariants = cva(
  'relative flex flex-col items-center justify-center gap-2 rounded-lg border-2 border-dashed border-input bg-background transition-all duration-200 outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2',
  {
    variants: {
      nVariant: {
        dropzone: 'w-full cursor-pointer hover:border-primary/60 hover:bg-accent/40',
        avatar: 'rounded-full cursor-pointer overflow-hidden hover:opacity-80',
      },
      nSize: {
        sm:      '',
        default: '',
        lg:      '',
      },
    },
    compoundVariants: [
      { nVariant: 'dropzone', nSize: 'sm',      class: 'min-h-28 p-4' },
      { nVariant: 'dropzone', nSize: 'default', class: 'min-h-40 p-6' },
      { nVariant: 'dropzone', nSize: 'lg',      class: 'min-h-52 p-8' },
      { nVariant: 'avatar',   nSize: 'sm',      class: 'h-16 w-16' },
      { nVariant: 'avatar',   nSize: 'default', class: 'h-24 w-24' },
      { nVariant: 'avatar',   nSize: 'lg',      class: 'h-32 w-32' },
    ],
    defaultVariants: {
      nVariant: 'dropzone',
      nSize: 'default',
    },
  },
);

export type ImageUploadVariants = VariantProps<typeof imageUploadVariants>;

export interface UploadFile {
  file: File;
  preview: string;
  name: string;
  size: number;
  type: string;
}

export interface UploadError {
  file: File;
  reason: 'size' | 'type' | 'dimensions' | 'count';
  message: string;
}

export const ACCEPT_PRESETS = {
  all:              '*/*',
  images:           'image/*',
