import { Component, signal } from '@angular/core';
import { ImageUploadComponent } from '../image-upload.component';

@Component({
  selector: 'demo-image-upload-progress',
  standalone: true,
  imports: [ImageUploadComponent],
  template: `
    <n-image-upload
      class="w-full max-w-lg"
      nLabel="Upload com progresso"
      nHint="Selecione uma imagem para simular o upload"
      nAccept="images"
      [nProgress]="progress()"
      (nFileSelect)="simulate()"
    />
  `,
})
export class ImageUploadProgressDemo {
  readonly progress = signal(-1);

  simulate(): void {
    this.progress.set(0);
    let pct = 0;
    const tick = setInterval(() => {
      pct += Math.floor(Math.random() * 12) + 4;
      if (pct >= 100) {
        this.progress.set(100);
        clearInterval(tick);
        setTimeout(() => this.progress.set(-1), 1200);
      } else {
        this.progress.set(pct);
      }
    }, 200);
  }
}

import { Component } from '@angular/core';
import { FormControl, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { ImageUploadComponent } from '../image-upload.component';
import type { UploadFile } from '../image-upload.types';

@Component({
  selector: 'demo-image-upload-reactive-form',
  standalone: true,
  imports: [ReactiveFormsModule, ImageUploadComponent],
  template: `
    <form [formGroup]="form" (ngSubmit)="submit()" class="flex flex-col gap-4 w-full max-w-lg">
      <n-image-upload
        nLabel="Foto de perfil"
        nAccept="images-raster"
        nHint="JPG, PNG ou WebP · máximo 2 MB"
        [nMaxSize]="2 * 1024 * 1024"
        [nRequired]="true"
        [formControl]="form.controls.photo"
      />
      <div class="flex gap-2">
        <button
          type="submit"
          class="rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground disabled:opacity-50"
          [disabled]="form.invalid"
        >Enviar</button>
        <button
          type="button"
          class="rounded-md border px-4 py-2 text-sm font-medium"
          (click)="reset()"
        >Limpar</button>
      </div>
      @if (submitted()) {
        <p class="text-xs text-muted-foreground">
          Enviado: {{ form.value.photo?.[0]?.name ?? '—' }}
        </p>
      }
    </form>
  `,
})
export class ImageUploadReactiveFormDemo {
  readonly form = new FormGroup({
    photo: new FormControl<UploadFile[]>([], {
      validators: [Validators.required, Validators.minLength(1)],
      nonNullable: true,
    }),
  });

  private _submitted = false;
  submitted() { return this._submitted; }

  submit(): void {
    this.form.markAllAsTouched();
    if (this.form.valid) {
      this._submitted = true;
    }
  }

  reset(): void {
    this.form.reset();
    this._submitted = false;
  }
}

